#include <stdio.h>

int main() {
    int A, B;
    scanf("%d %d", &A, &B);
    int a = 1;
    int min = A < B ? A : B;
    for (int i = 1; i <= min; i++) {
        a *= i;
    }
    printf("%d\n", a);
    return 0;
}
